/* BTBreadcrumb — Figma node 681:10168 (web D) */
/* All CSS vars verified against packages/tokens/platforms/web/bspace/dist/styles.css */

/* ── Nav wrapper ──────────────────────────────────────────────────────────── */

.bt-breadcrumb {
  display: flex;
  align-items: center;
}

/* ── Ordered list ─────────────────────────────────────────────────────────── */

.bt-breadcrumb-list {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--space-sm);
  list-style: none;
  margin: 0;
  padding: 0;
}

/* ── Individual item (li) ─────────────────────────────────────────────────── */

.bt-breadcrumb-item {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
}

/* ── Current (last) item — non-interactive ────────────────────────────────── */

.bt-breadcrumb-page {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: 1.14;
  color: var(--text-primary);
}

/* ── Separator icon ───────────────────────────────────────────────────────── */

.bt-breadcrumb-separator {
  display: inline-flex;
  align-items: center;
  color: var(--text-secondary);
}

.bt-breadcrumb-separator__icon {
  width: 6px;
  height: 10px;
}

[dir="rtl"] .bt-breadcrumb-separator__icon {
  transform: scaleX(-1);
}

/* ── Ellipsis trigger (···) ───────────────────────────────────────────────── */

.bt-breadcrumb-ellipsis {
  position: relative;
  display: inline-flex;
}

.bt-breadcrumb-ellipsis__btn {
  width: 24px;
  height: 24px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-sm);
  background: none;
  border: none;
  cursor: pointer;
  color: var(--text-secondary);
  padding: 0;
  transition: background 0.15s ease;
}

.bt-breadcrumb-ellipsis__btn:hover,
.bt-breadcrumb-ellipsis__btn[aria-expanded="true"] {
  background: var(--bg-secondary);
}

.bt-breadcrumb-ellipsis__icon {
  width: 16px;
  height: 4px;
}

/**
 * BTBreadcrumb — compositional breadcrumb root wrapper.
 * Figma: D node 681:10168.
 *
 * @example
 * ```tsx
 * <BTBreadcrumb>
 *   <BTBreadcrumbList>
 *     <BTBreadcrumbItem>
 *       <BTBreadcrumbLink href="/home">Home</BTBreadcrumbLink>
 *     </BTBreadcrumbItem>
 *     <BTBreadcrumbSeparator />
 *     <BTBreadcrumbItem>
 *       <BTBreadcrumbPage>Detail</BTBreadcrumbPage>
 *     </BTBreadcrumbItem>
 *   </BTBreadcrumbList>
 * </BTBreadcrumb>
 * ```
 */
import './BTBreadcrumb.css';
import type { BTBreadcrumbProps } from './BTBreadcrumb.types';

export function BTBreadcrumb({ children, className }: BTBreadcrumbProps) {
  return (
    <nav
      className={`bt-breadcrumb${className ? ` ${className}` : ''}`}
      aria-label="Breadcrumb"
    >
      {children}
    </nav>
  );
}

BTBreadcrumb.displayName = 'BTBreadcrumb';

// BTBreadcrumb compositional types — Figma node 681:10168 (web D).

import type { ReactNode } from 'react';

export interface BTBreadcrumbProps {
  className?: string;
  children?: ReactNode;
}

export interface BTBreadcrumbListProps {
  className?: string;
  children?: ReactNode;
}

export interface BTBreadcrumbItemProps {
  className?: string;
  children?: ReactNode;
}

export interface BTBreadcrumbLinkProps {
  /** URL to navigate to. When provided renders an <a> element. */
  href?: string;
  /** Programmatic press handler. When href is also set, prevents default navigation. */
  onPress?: () => void;
  className?: string;
  children?: ReactNode;
}

export interface BTBreadcrumbPageProps {
  className?: string;
  children?: ReactNode;
}

export interface BTBreadcrumbSeparatorProps {
  className?: string;
}

/** A single item shown inside the BTBreadcrumbEllipsis dropdown list. */
export interface BTBreadcrumbDropdownItem {
  /** Display label shown in the list row. */
  label: string;
  /** Called when the user selects this item. */
  onPress?: () => void;
}

export interface BTBreadcrumbEllipsisProps {
  /** Collapsed breadcrumb items shown inside the BTDropdownList dropdown. */
  items: BTBreadcrumbDropdownItem[];
  className?: string;
}

import { useMemo } from 'react';
import moreHorizIcon from './icons/more_horiz.svg';
import type { BTBreadcrumbEllipsisProps } from './BTBreadcrumb.types';
import { BTDropdown } from '../dropdown/BTDropdown';

export function BTBreadcrumbEllipsis({ items = [], className }: BTBreadcrumbEllipsisProps) {
  const dropdownItems = useMemo(
    () => items.map((item, i) => ({ value: i, label: item.label })),
    [items],
  );

  function handleSelect(index: number) {
    items[index]?.onPress?.();
  }

  return (
    <span className={`bt-breadcrumb-ellipsis${className ? ` ${className}` : ''}`}>
      <BTDropdown
        items={dropdownItems}
        align="start"
        onSelect={handleSelect}
        trigger={(toggle, isOpen) => (
          <button
            type="button"
            className="bt-breadcrumb-ellipsis__btn"
            aria-expanded={isOpen}
            aria-label="Show more breadcrumb items"
            onClick={toggle}
          >
            <img src={moreHorizIcon} className="bt-breadcrumb-ellipsis__icon" alt="" />
          </button>
        )}
      />
    </span>
  );
}

BTBreadcrumbEllipsis.displayName = 'BTBreadcrumbEllipsis';

import type { BTBreadcrumbItemProps } from './BTBreadcrumb.types';

export function BTBreadcrumbItem({ children, className }: BTBreadcrumbItemProps) {
  return (
    <li className={`bt-breadcrumb-item${className ? ` ${className}` : ''}`}>
      {children}
    </li>
  );
}

BTBreadcrumbItem.displayName = 'BTBreadcrumbItem';

import { BTButtonLink } from '../button-link/BTButtonLink';
import type { BTBreadcrumbLinkProps } from './BTBreadcrumb.types';

export function BTBreadcrumbLink({ href, onPress, className, children }: BTBreadcrumbLinkProps) {
  if (href) {
    function handleClick(e: React.MouseEvent<HTMLAnchorElement>) {
      if (onPress) {
        e.preventDefault();
        onPress();
      }
    }
    return (
      <a
        href={href}
        className={['bt-button-link', 'bt-button-link--secondary', className].filter(Boolean).join(' ')}
        onClick={handleClick}
      >
        <span className="bt-button-link__label">{children}</span>
      </a>
    );
  }

  return (
    <BTButtonLink
      label={String(children ?? '')}
      variant="secondary"
      className={className}
      onClick={onPress}
    />
  );
}

BTBreadcrumbLink.displayName = 'BTBreadcrumbLink';

import type { BTBreadcrumbListProps } from './BTBreadcrumb.types';

export function BTBreadcrumbList({ children, className }: BTBreadcrumbListProps) {
  return (
    <ol className={`bt-breadcrumb-list${className ? ` ${className}` : ''}`}>
      {children}
    </ol>
  );
}

BTBreadcrumbList.displayName = 'BTBreadcrumbList';

import type { BTBreadcrumbPageProps } from './BTBreadcrumb.types';

export function BTBreadcrumbPage({ children, className }: BTBreadcrumbPageProps) {
  return (
    <span
      className={`bt-breadcrumb-page${className ? ` ${className}` : ''}`}
      aria-current="page"
    >
      {children}
    </span>
  );
}

BTBreadcrumbPage.displayName = 'BTBreadcrumbPage';

import chevronRight from './icons/chevron_right.svg';
import type { BTBreadcrumbSeparatorProps } from './BTBreadcrumb.types';

export function BTBreadcrumbSeparator({ className }: BTBreadcrumbSeparatorProps) {
  return (
    <span
      className={`bt-breadcrumb-separator${className ? ` ${className}` : ''}`}
      aria-hidden="true"
    >
      <img src={chevronRight} className="bt-breadcrumb-separator__icon" alt="" />
    </span>
  );
}

BTBreadcrumbSeparator.displayName = 'BTBreadcrumbSeparator';

export { BTBreadcrumb } from './BTBreadcrumb';
export { BTBreadcrumbList } from './BTBreadcrumbList';
export { BTBreadcrumbItem } from './BTBreadcrumbItem';
export { BTBreadcrumbLink } from './BTBreadcrumbLink';
export { BTBreadcrumbPage } from './BTBreadcrumbPage';
export { BTBreadcrumbSeparator } from './BTBreadcrumbSeparator';
export { BTBreadcrumbEllipsis } from './BTBreadcrumbEllipsis';
export type {
  BTBreadcrumbProps,
  BTBreadcrumbListProps,
  BTBreadcrumbItemProps,
  BTBreadcrumbLinkProps,
  BTBreadcrumbPageProps,
  BTBreadcrumbSeparatorProps,
  BTBreadcrumbEllipsisProps,
  BTBreadcrumbDropdownItem,
} from './BTBreadcrumb.types';
